                        : 'max-h-0 opacity-0'
                }`}>
                    <div className="bg-white/95 backdrop-blur-2xl border-t border-gray-200/50 shadow-2xl">
                        <div className="px-6 py-8 space-y-6">
                            {/* Mobile Programs */}
                            <div className="relative">
                                <button
                                    onClick={() => toggleDropdown('courses')}
                                    className="flex items-center justify-between w-full px-6 py-4 text-gray-700 hover:text-blue-600 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 rounded-xl transition-all duration-500 group transform hover:scale-105"
                                >
                                    <div className="flex items-center space-x-3">
                                        <span className="font-semibold">
                                            {t('navigation.programs') || 'Programs'}
                                        </span>
                                        <span className="text-xl">🎓</span>
                                    </div>
                                    <ChevronDown className={`w-5 h-5 transition-all duration-500 ${
                                        dropdownOpen === 'courses' ? 'rotate-180 text-blue-500' : ''
                                    } group-hover:scale-110`} />
                                </button>
                                <div className={`transition-all duration-500 overflow-hidden ${
                                    dropdownOpen === 'courses' ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'
                                }`}>
                                    <div className="mt-3 pl-6 space-y-3">
                                        {coursesData.map((course, index) => (
                                            <Link
                                                key={index}
                                                to={course.path}
                                                className="flex items-center space-x-4 px-6 py-4 text-gray-600 hover:text-blue-600 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 rounded-xl transition-all duration-500 w-full text-left group transform hover:translate-x-2 hover:scale-105"
                                            >
                                                <div className={`w-10 h-10 rounded-xl bg-gradient-to-r ${course.gradient} flex items-center justify-center group-hover:scale-110 group-hover:rotate-12 transition-all duration-500`}>
                                                    <course.icon className="w-5 h-5 text-white" />
                                                </div>
                                                <div className="flex items-center space-x-2">
                                                    <span className="group-hover:translate-x-1 transition-transform duration-300 font-medium">{course.title}</span>
                                                    <span className="text-lg">{course.emoji}</span>
                                                </div>
                                            </Link>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            {/* Mobile About */}
                            <div className="relative">
                                <button
                                    onClick={() => toggleDropdown('about')}
                                    className="flex items-center justify-between w-full px-6 py-4 text-gray-700 hover:text-blue-600 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 rounded-xl transition-all duration-500 group transform hover:scale-105"
                                >
                                    <div className="flex items-center space-x-3">
                                        <span className="font-semibold">
                                            {t('navigation.about') || 'About'}
                                        </span>
                                        <span className="text-xl">🏛️</span>
                                    </div>
                                    <ChevronDown className={`w-5 h-5 transition-all duration-500 ${
                                        dropdownOpen === 'about' ? 'rotate-180 text-blue-500' : ''
                                    } group-hover:scale-110`} />
                                </button>

                                <div className={`transition-all duration-500 overflow-hidden ${
                                    dropdownOpen === 'about' ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'
                                }`}>
                                    <div className="mt-3 pl-6 space-y-3">
                                        {aboutLinks.map((link, index) => (
                                            <Link
                                                key={index}
                                                to={link.path}
                                                className="flex items-center space-x-4 px-6 py-3 text-gray-600 hover:text-blue-600 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 rounded-xl transition-all duration-500 w-full text-left group transform hover:translate-x-2 hover:scale-105"
                                            >
                                                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-gray-100 to-gray-200 flex items-center justify-center group-hover:bg-gradient-to-br group-hover:from-blue-100 group-hover:to-purple-100 transition-all duration-500 group-hover:rotate-12">
                                                    <link.icon className="w-4 h-4 text-gray-600 group-hover:text-blue-600 transition-colors duration-300" />
                                                </div>
                                                <div className="flex items-center space-x-2">
                                                    <span className="group-hover:translate-x-1 transition-transform duration-300 font-medium">{link.title}</span>
                                                    <span className="text-lg">{link.emoji}</span>
                                                </div>
                                            </Link>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            {/* Other mobile links */}
                            {navigationLinks.map((item) => (
                                <Link
                                    key={item.path}
                                    to={item.path}
                                    className="flex items-center space-x-3 w-full text-left px-6 py-4 text-gray-700 hover:text-blue-600 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 rounded-xl transition-all duration-500 font-semibold group transform hover:translate-x-2 hover:scale-105"
                                >
                                    <span className="text-xl">{item.emoji}</span>
                                    <span className="group-hover:translate-x-1 transition-transform duration-300 inline-block">
                                        {item.label}
                                    </span>
                                </Link>
                            ))}

                            {/* Enhanced Mobile Actions */}
                            <div className="pt-6 border-t border-gray-200/50 space-y-4">
                                <button
                                    onClick={onLoginClick}
                                    className="flex items-center space-x-3 w-full px-6 py-4 text-gray-700 hover:text-blue-600 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 rounded-xl transition-all duration-500 group transform hover:scale-105"
                                >
                                    <User className="w-5 h-5 group-hover:scale-125 group-hover:rotate-12 transition-all duration-500" />
                                    <span className="font-semibold group-hover:translate-x-1 transition-transform duration-300">
                                        {t('buttons.login') || 'Login'}
                                    </span>
                                </button>
                                <Link
                                    to="/apply"
                                    className="flex items-center justify-center space-x-3 w-full px-6 py-4 bg-gradient-to-r from-blue-500 via-purple-600 to-pink-500 text-white rounded-xl hover:from-blue-600 hover:via-purple-700 hover:to-pink-600 transition-all duration-500 font-bold group hover:shadow-2xl transform hover:scale-105 hover:-translate-y-1"
                                >
                                    <span className="text-xl group-hover:animate-bounce">🚀</span>
                                    <span>{t('buttons.applyNow') || 'Apply Now'}</span>
                                    <ArrowRight className="w-5 h-5 group-hover:translate-x-2 group-hover:scale-125 transition-all duration-500" />
                                </Link>
                            </div>
                        </div>
                    </div>
                </div>
            </header>

            {/* Login Modal */}
            <LoginModal
                isOpen={isLoginModalOpen}
                onClose={closeModal}
            />
        </>
    );
};

export default Header;
